  const actor = c.get("actor");
  const db = c.get("db");
  const sort = validateSort(c.req.query("sort"), ALLOWED_POST_SORTS, "recent");
  const limit = parseLimit(c.req.query("limit"), 50, 100);
  const offset = parseOffset(c.req.query("offset"), 0, 1e4);
