async function purgeObjects(db, apIds, media2) {
  if (apIds.length === 0) return;
  const mediaKeys = [];
  for (const apId of apIds) {
    mediaKeys.push(...await deleteObjectCascade(db, apId, media2));
  }
  for (const chunk of chunkForInClause(apIds)) {
    await db.delete(objects).where(inArray(objects.apId, chunk));
  }
  await purgeMediaBlobs(media2, mediaKeys);
}
async function purgeActorContent(db, blockedApId, media2) {
  try {
    const rows = await db.select({ apId: objects.apId }).from(objects).where(eq(objects.attributedTo, blockedApId));
    await purgeObjects(
      db,
      rows.map((r) => r.apId),
      media2
    );
    await db.delete(activities).where(eq(activities.actorApId, blockedApId));
  } catch (err) {
    log35.warn("blocklist.purgeActorContent failed", {
      event: "blocklist.purge_actor_failed",
      actor: blockedApId,
      error: err
    });
  }
}
async function purgeDomainContent(db, domainOrUrl, media2) {
  const domain = normalizeDomain(domainOrUrl);
  if (!domain) return;
  try {
    const hostMatch = or(
      like(objects.attributedTo, `https://${domain}/%`),
      like(objects.attributedTo, `https://%.${domain}/%`)
    );
    const rows = await db.select({ apId: objects.apId }).from(objects).where(hostMatch);
    await purgeObjects(
      db,
      rows.map((r) => r.apId),
      media2
    );
    await db.delete(activities).where(
      or(
        like(activities.actorApId, `https://${domain}/%`),
        like(activities.actorApId, `https://%.${domain}/%`)
      )
    );
  } catch (err) {
    log35.warn("blocklist.purgeDomainContent failed", {
      event: "blocklist.purge_domain_failed",
      domain,
      error: err
    });
  }
}

