// src/backend/middleware/bearer-auth.ts
function requireBearerAuth(requiredScope) {
  return async (c, next) => {
    const auth2 = c.req.header("Authorization");
    if (!auth2?.startsWith("Bearer ")) {
      return c.json({ error: "unauthorized" }, 401);
    }
    const token = auth2.slice(7);
    const issuer = getOidcIssuerUrl(c.env);
    const { clientId, clientSecret } = getOidcClientCredentials(c.env);
    if (!issuer || !clientId || !clientSecret) {
      return c.json(
        {
          error: "server_error",
          error_description: "Takosumi Accounts OIDC client not configured"
        },
        500
      );
    }
    const res = await fetch(issuerEndpoint(issuer, "/oauth/introspect"), {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: new URLSearchParams({
        token,
        client_id: clientId,
        client_secret: clientSecret
      }).toString()
    });
    if (!res.ok) {
      return c.json(
        {
          error: "server_error",
          error_description: "Introspect failed"
        },
        500
      );
    }
    const info = await res.json();
    if (!info.active) {
      return c.json({ error: "invalid_token" }, 401);
    }
    const scopes = (info.scope ?? "").split(" ");
    if (!scopes.includes(requiredScope)) {
      return c.json({ error: "insufficient_scope" }, 403);
    }
    c.set("oauthToken", {
      sub: info.sub ?? "",
      scope: info.scope ?? "",
      client_id: info.client_id ?? ""
    });
    await next();
  };
}

